import os
import re
import sys
import psycopg2
from psycopg2 import sql

EXTENSION_NAME_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")


def get_db_connection():
    return psycopg2.connect(
        host=os.getenv("PGHOST", "localhost"),
        port=os.getenv("PGPORT", "5432"),
        dbname=os.getenv("PGDATABASE", "postgres"),
        user=os.getenv("PGUSER", "postgres"),
        password=os.getenv("PGPASSWORD", ""),
    )


def validate_extension_name(extension_name):
    if not isinstance(extension_name, str):
        raise ValueError("Extension name must be a string")
    extension_name = extension_name.strip()
    if not extension_name:
        raise ValueError("Extension name cannot be empty")
    if not EXTENSION_NAME_RE.fullmatch(extension_name):
        raise ValueError("Invalid extension name")
    return extension_name


def create_extension(conn, extension_name, if_not_exists=True):
    extension_name = validate_extension_name(extension_name)
    query = sql.SQL("CREATE EXTENSION {}{}").format(
        sql.SQL("IF NOT EXISTS ") if if_not_exists else sql.SQL(""),
        sql.Identifier(extension_name),
    )
    with conn.cursor() as cur:
        cur.execute(query)
    conn.commit()


def list_available_extensions(conn):
    with conn.cursor() as cur:
        cur.execute("SELECT name, default_version, installed_version, comment FROM pg_available_extensions ORDER BY name")
        return cur.fetchall()


def list_installed_extensions(conn):
    with conn.cursor() as cur:
        cur.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname")
        return cur.fetchall()


